#include <stdio.h>
int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long age;
        if(scanf("%lld",&age)!=1) age=0;
        if(age%2==0) printf("Your age is even!\n");
        else printf("Your age is odd!\n");
    }
    return 0;
}

